defmodule AppWeb.Components.Sidebar do
  use Phoenix.Component
  import Phoenix.HTML

  @doc """
  Renders a sidebar component with toggle button.

  ## Examples

      <.sidebar>
        <:toggle>
          <span>Toggle Menu</span>
        </:toggle>
        <:content>
          <ul class="sidebar-menu">
            <li><a href="/">Dashboard</a></li>
            <li><a href="/settings">Settings</a></li>
          </ul>
        </:content>
      </.sidebar>

  """
  attr :id, :string, default: "sidebar"
  attr :class, :string, default: ""
  attr :content_class, :string, default: ""
  attr :toggle_class, :string, default: ""
  attr :default_open, :boolean, default: true

  slot :toggle, required: true
  slot :content, required: true

  def sidebar(assigns) do
    ~H"""
    <div
      x-data={~S|
        { 
          sidebarOpen: |} <> "#{@default_open}" <> ~S|, 
          touchStartX: 0,
          currentX: 0,
          swiping: false,
          sidebarTransform: 'translateX(0)',

          handleTouchStart(e) {
            if (!this.sidebarOpen) return;
            this.swiping = true;
            this.touchStartX = e.changedTouches[0].screenX;
            this.currentX = 0;
          },

          handleTouchMove(e) {
            if (!this.swiping || !this.sidebarOpen) return;

            const touchX = e.changedTouches[0].screenX;
            this.currentX = this.touchStartX - touchX;

            // Only allow swiping left (negative values)
            if (this.currentX > 0) {
              // Calculate how far the sidebar should move, capped at 100% width
              const sidebarWidth = this.$el.offsetWidth;
              const translateX = Math.max(-this.currentX, -sidebarWidth);
              this.sidebarTransform = `translateX(${translateX}px)`;
            }
          },

          handleTouchEnd(e) {
            if (!this.swiping || !this.sidebarOpen) return;

            const touchEndX = e.changedTouches[0].screenX;
            const swipeDistance = this.touchStartX - touchEndX;
            const sidebarWidth = this.$el.offsetWidth;

            // If swiped more than 40% of sidebar width, close it
            if (swipeDistance > sidebarWidth * 0.4) {
              this.sidebarOpen = false;
            }

            // Reset transform regardless
            this.sidebarTransform = 'translateX(0)';
            this.swiping = false;
          },

          cancelSwipe() {
            this.swiping = false;
            this.sidebarTransform = 'translateX(0)';
          }
        }
      |}
      id={@id}
      class={@class}
    >
      <!-- Toggle button -->
      <button 
        @click="sidebarOpen = !sidebarOpen" 
        class={"sidebar-toggle #{@toggle_class}"}
        aria-expanded="true"
        aria-controls="sidebar-content"
        aria-label="Toggle sidebar"
      >
        <%= render_slot(@toggle) %>
      </button>

      <!-- Sidebar with swipe behavior and dynamic transform -->
      <div 
        id="sidebar-content"
        x-show="sidebarOpen"
        @click.away="sidebarOpen = false"
        @touchstart="handleTouchStart"
        @touchmove="handleTouchMove"
        @touchend="handleTouchEnd"
        @touchcancel="cancelSwipe"
        class={"sidebar #{@content_class}"}
        :style="{ transform: sidebarTransform }"
        x-transition:enter="transition ease-out duration-300"
        x-transition:enter-start="opacity-0 transform -translate-x-full"
        x-transition:enter-end="opacity-100 transform translate-x-0"
        x-transition:leave="transition ease-in duration-300"
        x-transition:leave-start="opacity-100 transform translate-x-0"
        x-transition:leave-end="opacity-0 transform -translate-x-full"
        style="touch-action: pan-y;"
      >
        <%= render_slot(@content) %>
      </div>
    </div>
    """
  end
end
